"""OkrCategoria CRUD endpoints — generated by scripts/new_entity.py."""

from fastapi import APIRouter, Depends
from sqlalchemy.ext.asyncio import AsyncSession

from app.api.deps import get_current_user, get_db
from app.api.deps_ownership import require_ownership
from app.core.response import success
from app.models.user import User
from app.models.okr_categoria import OkrCategoria
from app.schemas.okr_categoria import OkrCategoriaCreate, OkrCategoriaRead, OkrCategoriaUpdate
from app.services.okr_categoria_service import okr_categoria_svc

router = APIRouter()


@router.get("")
async def list_okr_categorias(
    db: AsyncSession = Depends(get_db),
    current_user: User = Depends(get_current_user),
):
    """List okr_categorias owned by the current user."""
    items = await okr_categoria_svc.list(db, filters={"user_id": current_user.id})
    return success([OkrCategoriaRead.model_validate(x).model_dump(mode="json") for x in items])


@router.get("/{id}")
async def get_okr_categoria(
    entity: OkrCategoria = Depends(require_ownership(okr_categoria_svc)),
):
    """Get a single owned okr_categoria by ID (404 if not owned)."""
    return success(OkrCategoriaRead.model_validate(entity).model_dump(mode="json"))


@router.post("", status_code=201)
async def create_okr_categoria(
    entity_in: OkrCategoriaCreate,
    db: AsyncSession = Depends(get_db),
    current_user: User = Depends(get_current_user),
):
    """Create a new okr_categoria for the current user."""
    entity = await okr_categoria_svc.create(db, entity_in, extra={"user_id": current_user.id})
    return success(OkrCategoriaRead.model_validate(entity).model_dump(mode="json"))


@router.patch("/{id}")
async def update_okr_categoria(
    entity_in: OkrCategoriaUpdate,
    db: AsyncSession = Depends(get_db),
    current_user: User = Depends(get_current_user),
    entity: OkrCategoria = Depends(require_ownership(okr_categoria_svc)),
):
    """Partially update an owned okr_categoria (404 if not owned)."""
    updated = await okr_categoria_svc.update(
        db, entity.id, entity_in, scope={"user_id": current_user.id}
    )
    return success(OkrCategoriaRead.model_validate(updated).model_dump(mode="json"))


@router.delete("/{id}")
async def delete_okr_categoria(
    db: AsyncSession = Depends(get_db),
    current_user: User = Depends(get_current_user),
    entity: OkrCategoria = Depends(require_ownership(okr_categoria_svc)),
):
    """Delete an owned okr_categoria (404 if not owned)."""
    await okr_categoria_svc.delete(db, entity.id, scope={"user_id": current_user.id})
    return success(None, meta={"message": "OkrCategoria deleted"})
